mapper.select:
SELECT c.id AS categoryId, c.name AS categoryName, COUNT(a.id) AS articleCount, SUM(a.view_count) AS totalViews, SUM(a.like_count) AS totalLikes FROM sparkit_news_category c LEFT JOIN sparkit_news_article a ON c.id = a.category_id AND a.deleted = 0
AND a.publish_time >= #{startTime}
AND a.publish_time <= #{endTime}
WHERE c.deleted = 0 GROUP BY c.id, c.name ORDER BY articleCount DESC

SELECT DATE_FORMAT(publish_time, '%Y-%m-%d') AS date, COUNT(*) AS count, SUM(CASE WHEN ai_generated = 1 THEN 1 ELSE 0 END) AS aiCount FROM sparkit_news_article WHERE deleted = 0
AND publish_time >= #{startTime}
AND publish_time <= #{endTime}
GROUP BY DATE_FORMAT(publish_time, '%Y-%m-%d') ORDER BY date ASC
